#!/usr/bin/env node

/**
 * merge-improvements.js — Merge .tmp-improve-*.md files into a single IMPROVEMENT-P{N}.md.
 *
 * Replaces the Sonnet merge agent in the improve-phase pipeline. Deterministic:
 * parses items, renumbers sequentially, computes pipeline status via pipeline-classify.js,
 * writes the final file, summary JSON, and cleans up temp files.
 *
 * Usage:
 *   node scripts/merge-improvements.js --phase-dir <dir> --padded <NN> --pass <N> --expected <count>
 */

import { readFileSync, writeFileSync, readdirSync, unlinkSync, existsSync } from 'fs';
import path from 'path';
import { execSync } from 'child_process';
import { fileURLToPath } from 'url';

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

const args = process.argv.slice(2);

function getArg(name) {
  const idx = args.indexOf(`--${name}`);
  if (idx === -1 || idx + 1 >= args.length) return null;
  return args[idx + 1];
}

const phaseDir = getArg('phase-dir');
const paddedPhase = getArg('padded');
const passNumber = parseInt(getArg('pass') || '0', 10);
const expectedCount = parseInt(getArg('expected') || '0', 10);

if (!phaseDir || !paddedPhase || !passNumber) {
  console.error(`Usage: merge-improvements.js --phase-dir <dir> --padded <NN> --pass <N> --expected <count>`);
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Step 1: Read temp files and validate count
// ---------------------------------------------------------------------------

const warnings = [];
const tmpFiles = readdirSync(phaseDir)
  .filter(f => /^\.tmp-improve-.*\.md$/.test(f))
  .sort();

if (expectedCount > 0 && tmpFiles.length !== expectedCount) {
  const msg = `Expected ${expectedCount} temp files, found ${tmpFiles.length}`;
  console.error(`Warning: ${msg}`);
  warnings.push(msg);
}

if (tmpFiles.length === 0) {
  console.error('Error: No .tmp-improve-*.md files found');
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Step 2: Parse improvement items and convergence sections from each file
// ---------------------------------------------------------------------------

const allItems = [];
const convergenceSections = [];
const itemsPerArea = {};

for (const filename of tmpFiles) {
  const areaSlug = filename.replace(/^\.tmp-improve-/, '').replace(/\.md$/, '');
  const filePath = path.join(phaseDir, filename);
  const content = readFileSync(filePath, 'utf-8');
  const lines = content.split('\n');

  let areaCount = 0;
  let currentItem = null;
  let currentFieldName = null;
  let convergenceStart = -1;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Detect convergence assessment section
    if (/^##\s+Convergence Assessment/i.test(line)) {
      convergenceStart = i;
      if (currentItem) { allItems.push(currentItem); currentItem = null; areaCount++; }
      // Capture everything from here to end of file or next ## (non-convergence)
      let convergenceEnd = lines.length;
      for (let j = i + 1; j < lines.length; j++) {
        if (/^##\s+/.test(lines[j]) && !/^##\s+Convergence/i.test(lines[j])) {
          convergenceEnd = j;
          break;
        }
      }
      convergenceSections.push({
        area: areaSlug,
        content: lines.slice(i, convergenceEnd).join('\n'),
      });
      i = convergenceEnd - 1;
      continue;
    }

    // Detect item header: ### P{N}-IMP-{NN}: Title (and variants)
    const headerMatch = line.match(/^###\s+(P\d+-(?:IMP|ADV|SYN|CSC|ALN)(?:-[A-Z]*)?-\d+):\s*(.+)/);
    if (headerMatch) {
      if (currentItem) { allItems.push(currentItem); areaCount++; }
      currentItem = {
        id: headerMatch[1],
        title: headerMatch[2].trim(),
        area: areaSlug,
        fields: [],
      };
      currentFieldName = null;
      continue;
    }

    if (!currentItem) continue;

    // Parse **Field:** value
    const fieldMatch = line.match(/^\*\*(.+?):\*\*\s*(.*)/);
    if (fieldMatch) {
      currentFieldName = fieldMatch[1];
      currentItem.fields.push({ name: currentFieldName, value: fieldMatch[2] });
      continue;
    }

    // Continuation lines for multi-line fields
    if (currentFieldName && line.trim() !== '' && !/^###\s+/.test(line)) {
      const lastField = currentItem.fields[currentItem.fields.length - 1];
      if (lastField) {
        lastField.value += '\n' + line;
      }
      continue;
    }

    // Blank line resets field continuation
    if (line.trim() === '') {
      currentFieldName = null;
    }
  }

  if (currentItem) { allItems.push(currentItem); areaCount++; }
  itemsPerArea[areaSlug] = areaCount;
}

// ---------------------------------------------------------------------------
// Step 3: Renumber items sequentially
// ---------------------------------------------------------------------------

const renumbered = allItems.map((item, idx) => {
  const num = String(idx + 1).padStart(2, '0');
  return { ...item, newId: `P${passNumber}-IMP-${num}` };
});

// ---------------------------------------------------------------------------
// Helper: format a single item as markdown
// ---------------------------------------------------------------------------

function formatItem(item) {
  let md = `### ${item.newId}: ${item.title}\n`;
  for (const field of item.fields) {
    md += `**${field.name}:** ${field.value}\n`;
  }
  return md;
}

// ---------------------------------------------------------------------------
// Helper: format the full file content (without pipeline status)
// ---------------------------------------------------------------------------

function buildFileContent(pipelineSection) {
  const today = new Date().toISOString().slice(0, 10);
  let md = `# Improvement Pass ${passNumber}\n\n`;
  md += `**Date:** ${today}\n`;
  md += `**Phase:** ${paddedPhase}\n`;
  md += `**Status:** in-progress\n\n`;

  if (pipelineSection) {
    md += pipelineSection + '\n\n';
  }

  md += `## Improvements\n\n`;
  for (const item of renumbered) {
    md += formatItem(item) + '\n';
  }

  if (convergenceSections.length > 0) {
    for (const cs of convergenceSections) {
      md += `\n${cs.content}\n`;
    }
  }

  return md;
}

// ---------------------------------------------------------------------------
// Step 4-5: Write file, call pipeline-classify, rewrite with pipeline status
// ---------------------------------------------------------------------------

const outputFile = path.join(phaseDir, `IMPROVEMENT-P${passNumber}.md`);

// First write — without pipeline status (so pipeline-classify can read it)
writeFileSync(outputFile, buildFileContent(null), 'utf-8');

// Call pipeline-classify.js
let pipeline = null;
let pipelineSection = '';
try {
  const scriptDir = path.dirname(fileURLToPath(import.meta.url));
  const pipelineResult = execSync(
    `node ${path.join(scriptDir, 'pipeline-classify.js')} --phase-dir "${phaseDir}" --padded "${paddedPhase}" --json`,
    { encoding: 'utf-8' }
  );
  pipeline = JSON.parse(pipelineResult);

  const items = pipeline.items || {};
  const gaps = pipeline.gaps || {};
  const blockerList = (arr) => arr && arr.length > 0 ? arr.join(', ') : '\u2014';

  pipelineSection = `## Pipeline Status\n\n`;
  pipelineSection += `| Stage | Pending | Done | Blockers |\n`;
  pipelineSection += `|-------|---------|------|----------|\n`;
  pipelineSection += `| Prerequisites | ${items.prereqs_pending || 0} | ${items.prereqs_built || 0} | ${blockerList(pipeline.item_ids?.prereqs_pending)} |\n`;
  pipelineSection += `| Research | ${items.research_pending || 0} | ${items.research_done || 0} | ${blockerList(pipeline.item_ids?.research_pending)} |\n`;
  pipelineSection += `| Gaps | ${gaps.active || 0} | ${gaps.resolved || 0} | ${gaps.disputed > 0 ? `${gaps.disputed} disputed` : '\u2014'} |\n`;
  pipelineSection += `| Merge-ready | ${items.mergeable || 0} | ${items.implemented || 0} | \u2014 |\n`;
  pipelineSection += `\n**Pipeline:** ${pipeline.pipeline_string || 'unknown'}\n`;
  pipelineSection += `**Next:** ${pipeline.routing?.command || '(none)'} \u2014 ${pipeline.routing?.reason || 'unknown'}`;
} catch (err) {
  const msg = `pipeline-classify.js failed: ${err.message}`;
  console.error(`Warning: ${msg}`);
  warnings.push(msg);
}

// Step 6: Rewrite with pipeline status
writeFileSync(outputFile, buildFileContent(pipelineSection || null), 'utf-8');

// ---------------------------------------------------------------------------
// Step 7: Write .tmp-merge-summary.json
// ---------------------------------------------------------------------------

const summary = {
  pass: passNumber,
  total_items: renumbered.length,
  items_per_area: itemsPerArea,
  pipeline: {
    prereqs_pending: pipeline?.items?.prereqs_pending || 0,
    research_pending: pipeline?.items?.research_pending || 0,
    mergeable: pipeline?.items?.mergeable || 0,
    implemented: pipeline?.items?.implemented || 0,
  },
  warnings,
};

const summaryPath = path.join(phaseDir, '.tmp-merge-summary.json');
writeFileSync(summaryPath, JSON.stringify(summary, null, 2), 'utf-8');

// ---------------------------------------------------------------------------
// Step 8: Clean up temp files
// ---------------------------------------------------------------------------

for (const filename of tmpFiles) {
  try {
    unlinkSync(path.join(phaseDir, filename));
  } catch (err) {
    warnings.push(`Failed to delete ${filename}: ${err.message}`);
  }
}

// ---------------------------------------------------------------------------
// Output summary to stdout
// ---------------------------------------------------------------------------

console.log(JSON.stringify(summary, null, 2));

#!/usr/bin/env node

/**
 * pipeline-classify.js — Deterministic pipeline classification for MSD improvement pipeline.
 *
 * Replaces all formula-based computation currently done by LLMs. Parses IMPROVEMENT-P*.md
 * files, applies classification formulas from pipeline-classification.md, computes pipeline
 * string, applies routing decision table, detects auto-fix candidates, and computes
 * convergence metrics.
 *
 * Usage:
 *   node scripts/pipeline-classify.js --phase-dir .planning/phases/06-intent-review --padded 06
 *
 * Output: writes .tmp-pipeline.json to phase_dir and prints JSON to stdout.
 */

import { readFileSync, writeFileSync, readdirSync, existsSync, statSync } from 'fs';
import path from 'path';

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

const args = process.argv.slice(2);

function getArg(name) {
  const idx = args.indexOf(`--${name}`);
  if (idx === -1 || idx + 1 >= args.length) return null;
  return args[idx + 1];
}

const phaseDir = getArg('phase-dir');
const paddedPhase = getArg('padded');
const doFix = args.includes('--fix');
const doDedup = args.includes('--dedup');
const doIntegrity = args.includes('--integrity');
const jsonOnly = args.includes('--json');

if (!phaseDir || !paddedPhase) {
  console.error(`Usage: pipeline-classify.js --phase-dir <dir> --padded <NN> [--fix] [--json] [--dedup] [--integrity]

Options:
  --phase-dir   Path to phase directory (e.g., .planning/phases/06-intent-review)
  --padded      Zero-padded phase number (e.g., 06)
  --fix         Apply deterministic auto-fixes to files
  --json        Output JSON only (no summary)
  --integrity   Run structural integrity checks (wave inversions, file conflicts)
  --dedup       Detect cross-pass duplicates and similarity hints
  --dedup --fix Apply dedup supersessions to files

Example:
  node scripts/pipeline-classify.js --phase-dir .planning/phases/06-intent-review --padded 06
  node scripts/pipeline-classify.js --phase-dir .planning/phases/06-intent-review --padded 06 --dedup --json`);
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Constants — status groups from pipeline-classification.md
// ---------------------------------------------------------------------------

const ACTIVE_STATUSES = new Set(['open', 'enhanced', 'confirmed', 'prerequisite']);
const TRANSITIONAL_STATUSES = new Set(['researched', 'pre-implemented']);
const TERMINAL_STATUSES = new Set([
  'implemented', 'rejected', 'reframed', 'superseded', 'deferred', 'not-needed', 'failed',
]);
const ALL_STATUSES = new Set([...ACTIVE_STATUSES, ...TRANSITIONAL_STATUSES, ...TERMINAL_STATUSES]);

// ---------------------------------------------------------------------------
// Parsing helpers
// ---------------------------------------------------------------------------

/** Parse all improvement items from a single IMPROVEMENT-P*.md file. */
function parseImprovementFile(filePath) {
  const content = readFileSync(filePath, 'utf-8');
  const lines = content.split('\n');
  const items = [];
  let currentItem = null;
  let fileStatus = 'in-progress';

  // Extract file-level status
  const statusMatch = content.match(/^\*\*Status:\*\*\s*(.+)$/m);
  if (statusMatch) {
    fileStatus = statusMatch[1].trim().toLowerCase();
  }

  // Extract pass number from filename
  const passMatch = path.basename(filePath).match(/IMPROVEMENT-P(\d+)\.md/);
  const passNumber = passMatch ? parseInt(passMatch[1], 10) : 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Detect item header: ### P{N}-IMP-XX: Title (or ADV, SYN, CSC, ALN variants)
    const headerMatch = line.match(/^###\s+(P\d+-(?:IMP|ADV|SYN|CSC|ALN)(?:-[A-Z]*)?-\d+):\s*(.+)/);
    if (headerMatch) {
      if (currentItem) items.push(currentItem);
      currentItem = {
        id: headerMatch[1],
        title: headerMatch[2].trim(),
        line: i + 1,
        file: filePath,
        pass: passNumber,
        // Field defaults
        target: null,
        what: null,
        why: null,
        how: null,
        impacts: null,
        research_needed: false,
        research_needed_raw: null,
        confidence: null,
        prior_art: null,
        prerequisite: false,
        prerequisite_raw: null,
        depends_on_plans: null,
        classification: null,
        status: 'open',
        status_raw: null,
        adversarial_note: false,
        review_status: null,
        superseded_by: null,
        replaces: null,
        research_summary: null,
        pre_implement_note: null,
        origin: null,
      };
      continue;
    }

    if (!currentItem) continue;

    // Parse fields using **Field:** pattern
    const fieldMatch = line.match(/^\*\*(.+?):\*\*\s*(.*)/);
    if (fieldMatch) {
      const fieldName = fieldMatch[1].trim().toLowerCase();
      // Collect multi-line field value: continue reading subsequent lines that are
      // NOT blank, NOT a new field (**...**), and NOT a new item header (###)
      let fieldValue = fieldMatch[2].trim();
      let j = i + 1;
      while (j < lines.length) {
        const nextLine = lines[j];
        if (nextLine.trim() === '' || /^\*\*.+?:\*\*/.test(nextLine) || /^###\s+/.test(nextLine)) break;
        fieldValue += '\n' + nextLine;
        j++;
      }
      // Advance the loop index past continuation lines
      i = j - 1;

      switch (fieldName) {
        case 'target':
          currentItem.target = fieldValue;
          break;
        case 'what':
          currentItem.what = fieldValue;
          break;
        case 'why':
          currentItem.why = fieldValue;
          break;
        case 'how':
          currentItem.how = fieldValue;
          break;
        case 'impacts':
          currentItem.impacts = fieldValue;
          break;
        case 'research needed':
          currentItem.research_needed_raw = fieldValue;
          currentItem.research_needed = /^yes/i.test(fieldValue);
          break;
        case 'confidence':
          currentItem.confidence = fieldValue.toUpperCase().replace(/[^A-Z]/g, '').slice(0, 6);
          break;
        case 'prior art':
          currentItem.prior_art = fieldValue;
          break;
        case 'prerequisite':
          currentItem.prerequisite_raw = fieldValue;
          currentItem.prerequisite = /^yes/i.test(fieldValue);
          break;
        case 'depends on plans':
          currentItem.depends_on_plans = fieldValue;
          break;
        case 'classification':
          currentItem.classification = fieldValue.toLowerCase().trim();
          break;
        case 'status':
          currentItem.status_raw = fieldValue;
          currentItem.status = fieldValue.toLowerCase().trim().split(/\s/)[0]; // first word
          break;
        case 'adversarial note':
          currentItem.adversarial_note = true;
          break;
        case 'review status':
          currentItem.review_status = fieldValue.toLowerCase().trim();
          break;
        case 'superseded_by':
        case 'superseded by':
          currentItem.superseded_by = fieldValue;
          break;
        case 'research_summary':
        case 'research summary':
          currentItem.research_summary = fieldValue;
          break;
        case 'pre-implement note':
          currentItem.pre_implement_note = fieldValue;
          break;
        case 'replaces':
          currentItem.replaces = fieldValue;
          break;
        case 'components':
          currentItem.components = fieldValue;
          break;
        case 'trigger':
          currentItem.trigger = fieldValue;
          break;
        case 'origin':
          currentItem.origin = fieldValue.toLowerCase().trim();
          break;
      }
    }
  }

  if (currentItem) items.push(currentItem);

  return { items, fileStatus, passNumber, filePath };
}

/** Parse gap files from gaps/ directory. */
function parseGaps(gapsDir) {
  const gaps = { active: 0, disputed: 0, resolved: 0, files: [] };

  if (!existsSync(gapsDir)) return gaps;

  // Active/disputed gaps
  const activeFiles = readdirSync(gapsDir).filter(f => f.endsWith('.md') && f !== 'done');
  for (const f of activeFiles) {
    const fullPath = path.join(gapsDir, f);
    if (!statSync(fullPath).isFile()) continue;
    const content = readFileSync(fullPath, 'utf-8');
    const statusMatch = content.match(/^\*\*Status:\*\*\s*(.+)$/m);
    const status = statusMatch ? statusMatch[1].trim().toLowerCase() : 'active';

    if (status.includes('disputed')) {
      gaps.disputed++;
      gaps.files.push({ file: f, status: 'disputed' });
    } else {
      gaps.active++;
      gaps.files.push({ file: f, status: 'active' });
    }
  }

  // Resolved gaps (in done/ subdirectory)
  const doneDir = path.join(gapsDir, 'done');
  if (existsSync(doneDir)) {
    const doneFiles = readdirSync(doneDir).filter(f => f.endsWith('.md'));
    gaps.resolved = doneFiles.length;
  }

  return gaps;
}

/** Check CONTEXT.md status. */
function checkContext(phaseDir, paddedPhase) {
  const contextFile = path.join(phaseDir, `${paddedPhase}-CONTEXT.md`);

  if (!existsSync(contextFile)) {
    return { exists: false, status: 'missing', file: contextFile };
  }

  const content = readFileSync(contextFile, 'utf-8');
  const statusMatch = content.match(/^\*\*Status:\*\*\s*(.+)$/m);
  const status = statusMatch ? statusMatch[1].trim().toLowerCase() : 'unknown';

  return {
    exists: true,
    status: status === 'draft' ? 'draft' : 'aligned',
    file: contextFile,
    lines: content.split('\n').length,
  };
}

/** Check for existing plans. */
function checkPlans(phaseDir) {
  const plans = { count: 0, executed: false, files: [] };

  if (!existsSync(phaseDir)) return plans;

  const files = readdirSync(phaseDir).filter(f => /PLAN.*\.md$/i.test(f) && !f.includes('EXPECTED'));
  plans.count = files.length;
  plans.files = files;

  // Check for execution markers (may be prefixed with padded phase number)
  const allFiles = existsSync(phaseDir) ? readdirSync(phaseDir) : [];
  if (allFiles.some(f => /VERIFICATION\.md$/i.test(f))) {
    plans.executed = true;
  }

  return plans;
}

// ---------------------------------------------------------------------------
// Integrity checks (--integrity flag)
// ---------------------------------------------------------------------------

/**
 * checkIntegrity — deterministic structural checks on plan frontmatter.
 *
 * Checks:
 * 1. Wave-dependency inversions: a plan's depends_on references a plan in a wave >= its own wave.
 * 2. Same-wave file conflicts: two plans in the same wave list the same file in files_modified.
 *
 * Reads plan frontmatter via gsd-tools if available; falls back to inline YAML parsing.
 * No LLM involved — purely deterministic graph traversal.
 */
function checkIntegrity(phaseDir, paddedPhase) {
  const report = {
    wave_inversions: [],
    file_conflicts: [],
    plans_checked: 0,
    error: null,
  };

  if (!existsSync(phaseDir)) {
    report.error = `Phase directory not found: ${phaseDir}`;
    return report;
  }

  const planFiles = readdirSync(phaseDir)
    .filter(f => /PLAN.*\.md$/i.test(f) && !f.includes('EXPECTED'))
    .sort();

  if (planFiles.length === 0) return report;

  // Parse frontmatter from each plan file (inline YAML extraction — no gsd-tools dependency)
  const plans = [];
  for (const planFile of planFiles) {
    const planPath = path.join(phaseDir, planFile);
    try {
      const content = readFileSync(planPath, 'utf-8');
      const fm = extractFrontmatter(content);
      if (!fm) continue;

      // Extract plan ID from filename: {padded}-{NN}-PLAN.md → NN
      const idMatch = planFile.match(/(\d{2})-PLAN\.md$/i);
      const planId = idMatch ? idMatch[1] : planFile;

      plans.push({
        id: planId,
        file: planFile,
        wave: parseIntField(fm.wave),
        depends_on: parseListField(fm.depends_on),
        files_modified: parseListField(fm.files_modified),
      });
    } catch (e) {
      // Skip unreadable plans
    }
  }

  report.plans_checked = plans.length;

  // Build lookup: planId → wave
  const waveByPlan = new Map();
  for (const p of plans) {
    if (p.wave !== null) waveByPlan.set(p.id, p.wave);
  }

  // Check 1: Wave-dependency inversions
  // A plan depends_on another plan in a wave >= its own wave (cycle or wrong ordering)
  for (const plan of plans) {
    if (plan.wave === null) continue;
    for (const dep of plan.depends_on) {
      // depends_on may reference plan IDs directly (e.g., "01", "02") or file names
      const depId = dep.replace(/[^0-9]/g, '').padStart(2, '0').slice(-2) || dep;
      const depWave = waveByPlan.get(depId) ?? waveByPlan.get(dep);
      if (depWave === null || depWave === undefined) continue;
      if (depWave >= plan.wave) {
        report.wave_inversions.push({
          plan: plan.id,
          plan_wave: plan.wave,
          depends_on: dep,
          dep_wave: depWave,
          severity: depWave > plan.wave ? 'ERROR' : 'WARNING',
          message: depWave > plan.wave
            ? `Plan ${plan.id} (wave ${plan.wave}) depends on plan ${dep} (wave ${depWave}) — dependency is in a LATER wave (inversion)`
            : `Plan ${plan.id} (wave ${plan.wave}) depends on plan ${dep} in the SAME wave — potential deadlock`,
        });
      }
    }
  }

  // Check 2: Same-wave file conflicts
  // Two plans in the same wave both list the same file in files_modified
  const waveGroups = new Map();
  for (const plan of plans) {
    if (plan.wave === null) continue;
    if (!waveGroups.has(plan.wave)) waveGroups.set(plan.wave, []);
    waveGroups.get(plan.wave).push(plan);
  }

  for (const [wave, wavePlans] of waveGroups) {
    if (wavePlans.length < 2) continue;
    // Build file → plans map for this wave
    const fileOwners = new Map();
    for (const plan of wavePlans) {
      for (const file of plan.files_modified) {
        if (!file.trim()) continue;
        const normalizedFile = file.trim();
        if (!fileOwners.has(normalizedFile)) fileOwners.set(normalizedFile, []);
        fileOwners.get(normalizedFile).push(plan.id);
      }
    }
    for (const [file, owners] of fileOwners) {
      if (owners.length > 1) {
        report.file_conflicts.push({
          file,
          wave,
          plans: owners,
          severity: 'WARNING',
          message: `File "${file}" listed in files_modified of ${owners.length} plans in wave ${wave}: ${owners.join(', ')} — potential merge conflict`,
        });
      }
    }
  }

  return report;
}

/** Extract YAML frontmatter block (between --- delimiters) from markdown content. */
function extractFrontmatter(content) {
  const match = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  if (!match) return null;
  // Simple key: value YAML parser (no nested objects needed here)
  const fm = {};
  const lines = match[1].split('\n');
  let currentKey = null;
  let currentList = null;
  for (const line of lines) {
    // Detect list item under current key
    const listItemMatch = line.match(/^  - (.+)$/);
    if (listItemMatch && currentList !== null) {
      currentList.push(listItemMatch[1].trim().replace(/^['"]|['"]$/g, ''));
      continue;
    }
    // Detect key: value
    const kvMatch = line.match(/^(\w[\w_-]*):\s*(.*)/);
    if (kvMatch) {
      currentKey = kvMatch[1];
      const val = kvMatch[2].trim();
      if (val === '' || val === '[]' || val === 'null') {
        fm[currentKey] = val === '[]' ? [] : null;
        currentList = val === '[]' ? fm[currentKey] : null;
      } else if (val.startsWith('[')) {
        // Inline list: [a, b, c]
        fm[currentKey] = val.slice(1, -1).split(',').map(v => v.trim().replace(/^['"]|['"]$/g, '')).filter(Boolean);
        currentList = null;
      } else {
        fm[currentKey] = val.replace(/^['"]|['"]$/g, '');
        currentList = null;
      }
      continue;
    }
    // Multi-line list under current key (dash at depth 0 or 2)
    const topListItem = line.match(/^- (.+)$/);
    if (topListItem && currentKey) {
      if (!Array.isArray(fm[currentKey])) {
        fm[currentKey] = [];
      }
      fm[currentKey].push(topListItem[1].trim().replace(/^['"]|['"]$/g, ''));
      currentList = fm[currentKey];
      continue;
    }
    currentList = null;
  }
  return fm;
}

function parseIntField(val) {
  if (val === null || val === undefined) return null;
  const n = parseInt(String(val), 10);
  return isNaN(n) ? null : n;
}

function parseListField(val) {
  if (!val) return [];
  if (Array.isArray(val)) return val.filter(Boolean);
  if (typeof val === 'string') {
    // Could be comma-separated or a single value
    return val.split(',').map(v => v.trim()).filter(Boolean);
  }
  return [];
}

// ---------------------------------------------------------------------------
// Classification formulas (from pipeline-classification.md)
// ---------------------------------------------------------------------------

function classifyItems(allItems) {
  const result = {
    total: allItems.length,
    // Prerequisites
    prereqs_all: [],
    prereqs_miscategorized: [],
    prereqs_pending: [],
    prereqs_built: [],
    research_dependent_prereqs: [],
    prereqs_ready: [],
    // Research
    research_pending: [],
    research_done: [],
    research_only: [],
    // Review status
    adv_unvalidated: [],
    imp_unreviewed: [],
    // Merge
    mergeable: [],
    // Terminal
    implemented: [],
    reframed: [],
    rejected: [],
    deferred: [],
    not_needed: [],
    failed_items: [],
    // Active
    open_items: [],
  };

  for (const item of allItems) {
    const s = item.status;
    const preimplTerminal = new Set(['pre-implemented', 'deferred', 'not-needed', 'failed']);

    // prereqs_all: (prerequisite: yes OR status: prerequisite) AND status NOT terminal for prereqs
    if ((item.prerequisite || s === 'prerequisite') && !preimplTerminal.has(s)) {
      result.prereqs_all.push(item);
    }

    // prereqs_built
    if (s === 'pre-implemented') {
      result.prereqs_built.push(item);
    }

    // Terminal/transitional classification
    if (s === 'implemented') result.implemented.push(item);
    if (s === 'reframed') result.reframed.push(item);
    if (s === 'rejected' || s === 'superseded') result.rejected.push(item);
    if (s === 'deferred') result.deferred.push(item);
    if (s === 'not-needed') result.not_needed.push(item);
    if (s === 'failed') result.failed_items.push(item);
    if (s === 'open') result.open_items.push(item);

    // research_pending: research_needed: yes AND status not in resolved set
    const researchTerminal = new Set(['researched', 'implemented', 'rejected', 'not-needed', 'failed', 'deferred']);
    if (item.research_needed && !researchTerminal.has(s)) {
      result.research_pending.push(item);
    }

    // research_done
    if (s === 'researched') {
      result.research_done.push(item);
    }

    // adv_unvalidated: non-IMP prefix, status: open, no adversarial note
    const nonImpMatch = item.id.match(/P\d+-(ADV|SYN|CSC|ALN)/);
    if (nonImpMatch && s === 'open' && !item.adversarial_note) {
      result.adv_unvalidated.push(item);
    }

    // imp_unreviewed: IMP items, status: open
    const impMatch = item.id.match(/P\d+-IMP-/);
    if (impMatch && s === 'open') {
      result.imp_unreviewed.push(item);
    }
  }

  // prereqs_miscategorized: prereqs where target is CONTEXT or RESEARCH
  result.prereqs_miscategorized = result.prereqs_all.filter(
    item => item.target && /^(CONTEXT|RESEARCH)$/i.test(item.target.trim())
  );

  // prereqs_pending = prereqs_all - miscategorized
  const miscatIds = new Set(result.prereqs_miscategorized.map(i => i.id));
  result.prereqs_pending = result.prereqs_all.filter(i => !miscatIds.has(i.id));

  // research_dependent_prereqs: items in prereqs_pending with research_needed: yes
  // AND status not in resolved set
  const rdpTerminal = new Set(['researched', 'pre-implemented', 'deferred', 'not-needed', 'failed']);
  result.research_dependent_prereqs = result.prereqs_pending.filter(
    item => item.research_needed && !rdpTerminal.has(item.status)
  );

  // prereqs_ready = prereqs_pending - research_dependent_prereqs
  const rdpIds = new Set(result.research_dependent_prereqs.map(i => i.id));
  result.prereqs_ready = result.prereqs_pending.filter(i => !rdpIds.has(i.id));

  // research_only: prerequisite: no, research_needed: yes, status not terminal
  const resOnlyTerminal = new Set(['researched', 'implemented', 'rejected', 'not-needed', 'failed', 'deferred']);
  result.research_only = allItems.filter(
    item => !item.prerequisite && item.research_needed && !resOnlyTerminal.has(item.status)
  );

  // mergeable: status in (open, confirmed, enhanced, researched, pre-implemented)
  // AND NOT adv_unvalidated, AND NOT imp_unreviewed
  // AND NOT (research_needed: yes AND status != researched) — unresolved research
  // AND NOT (prerequisite: yes AND status != pre-implemented) — unbuilt prereqs
  const mergeableStatuses = new Set(['open', 'confirmed', 'enhanced', 'researched', 'pre-implemented']);
  const advUnvalIds = new Set(result.adv_unvalidated.map(i => i.id));
  const impUnrevIds = new Set(result.imp_unreviewed.map(i => i.id));
  result.mergeable = allItems.filter(
    item => mergeableStatuses.has(item.status)
      && !advUnvalIds.has(item.id)
      && !impUnrevIds.has(item.id)
      && !(item.research_needed === true && item.status !== 'researched')
      && !(item.prerequisite === true && item.status !== 'pre-implemented')
  );

  return result;
}

// ---------------------------------------------------------------------------
// Pipeline string computation
// ---------------------------------------------------------------------------

function computePipelineString(classified, context, gaps, plans) {
  const sym = (cond_check, cond_progress, cond_blocker, cond_na) => {
    if (cond_na) return '—';
    if (cond_blocker) return '!';
    if (cond_check) return '✓';
    if (cond_progress) return '~';
    return '—';
  };

  const hasImpFiles = classified.total > 0;
  const noOpenItems = classified.open_items.length === 0;
  const hasPrereqs = classified.prereqs_all.length > 0 || classified.prereqs_built.length > 0;
  const hasResearchNeeds = classified.research_pending.length > 0 ||
                            classified.research_done.length > 0 ||
                            gaps.active > 0;

  const discuss = context.exists
    ? (context.status === 'draft' ? '~' : '✓')
    : '—';

  const improve = !hasImpFiles ? '—'
    : classified.imp_unreviewed.length > 0 ? '!'
    : (noOpenItems && classified.imp_unreviewed.length === 0) ? '✓'
    : '~';

  const preImpl = !hasPrereqs ? '—'
    : (classified.prereqs_built.length > 0 && classified.prereqs_pending.length === 0) ? '✓'
    : classified.prereqs_pending.length > 0 ? '!'
    : '—';

  const research = !hasResearchNeeds ? '—'
    : gaps.disputed > 0 ? '!'
    : (classified.research_done.length > 0 &&
       classified.research_pending.length === 0 &&
       gaps.active === 0) ? '✓'
    : '~';

  const implement = classified.implemented.length === 0 && classified.mergeable.length === 0 ? '—'
    : (classified.implemented.length > 0 && classified.mergeable.length === 0) ? '✓'
    : '~';

  const plan = plans.count > 0 ? '✓' : '—';
  const execute = plans.executed ? '✓' : '—';

  return `[discuss] ${discuss} → [improve] ${improve} → [pre-impl] ${preImpl} → [research] ${research} → [implement] ${implement} → [plan] ${plan} → [execute] ${execute}`;
}

// ---------------------------------------------------------------------------
// Routing decision table
// ---------------------------------------------------------------------------

function computeRouting(classified, context, gaps, plans, paddedPhase, allItems = []) {
  const phase = paddedPhase;

  // Rule 1: No CONTEXT.md
  if (!context.exists) {
    return { rule: 1, command: `/msd:discuss-phase ${phase}`, reason: 'No CONTEXT.md found' };
  }

  // Rule 2: CONTEXT is draft
  if (context.status === 'draft') {
    return { rule: 2, command: `/msd:discuss-phase ${phase}`, reason: 'CONTEXT.md is draft' };
  }

  // Rule 3: No improvement files
  if (classified.total === 0) {
    return { rule: 3, command: `/msd:improve-phase ${phase}`, reason: 'No improvement files' };
  }

  // Rule 3.3: Unreviewed IMP items
  if (classified.imp_unreviewed.length > 0) {
    return {
      rule: 3.3,
      command: `/msd:resolve-blockers ${phase}`,
      reason: `${classified.imp_unreviewed.length} IMP item(s) never adversarially reviewed`,
    };
  }

  // Rule 3.5: Unvalidated ADV/SYN/CSC/ALN items
  if (classified.adv_unvalidated.length > 0) {
    return {
      rule: 3.5,
      command: `/msd:resolve-blockers ${phase}`,
      reason: `${classified.adv_unvalidated.length} non-IMP item(s) unvalidated`,
    };
  }

  // Rule 3.7: Miscategorized prerequisites
  if (classified.prereqs_miscategorized.length > 0) {
    return {
      rule: 3.7,
      command: `/msd:implement-improvements ${phase}`,
      reason: `${classified.prereqs_miscategorized.length} prerequisite(s) miscategorized (CONTEXT/RESEARCH target)`,
    };
  }

  // Rule 4: Any blockers
  const hasBlockers = classified.prereqs_pending.length > 0
    || classified.research_pending.length > 0
    || gaps.active > 0
    || gaps.disputed > 0;
  if (hasBlockers) {
    const reasons = [];
    if (classified.prereqs_pending.length > 0) reasons.push(`${classified.prereqs_pending.length} prereq(s) pending`);
    if (classified.research_pending.length > 0) reasons.push(`${classified.research_pending.length} research pending`);
    if (gaps.active > 0) reasons.push(`${gaps.active} gap(s) active`);
    if (gaps.disputed > 0) reasons.push(`${gaps.disputed} gap(s) disputed`);
    return {
      rule: 4,
      command: `/msd:resolve-blockers ${phase}`,
      reason: reasons.join(', '),
    };
  }

  // Rule 4.5: Reframed without replacement — only fire for orphaned reframes
  if (classified.reframed.length > 0) {
    // Check which reframed items actually have a replacement ADV item
    const orphanedReframes = classified.reframed.filter(reframedItem => {
      // Look for any ADV item with `replaces:` pointing to this reframed item
      const replacement = allItems.find(candidate =>
        candidate.id !== reframedItem.id &&
        candidate.replaces &&
        candidate.replaces.includes(reframedItem.id)
      );
      if (!replacement) return true; // orphaned — no replacement exists
      // If replacement exists but is in a terminal state, it's effectively orphaned
      if (TERMINAL_STATUSES.has(replacement.status)) return true;
      return false; // replacement exists and is active/transitional
    });

    if (orphanedReframes.length > 0) {
      return {
        rule: 4.5,
        command: `/msd:improve-phase ${phase}`,
        reason: `${orphanedReframes.length} reframed item(s) without replacement`,
      };
    }
  }

  // Rule 5: Failed items
  if (classified.failed_items.length > 0) {
    return {
      rule: 5,
      command: null,
      reason: `${classified.failed_items.length} failed item(s) — manual intervention needed`,
    };
  }

  // Rule 6: Mergeable items
  if (classified.mergeable.length > 0) {
    return {
      rule: 6,
      command: `/msd:implement-improvements ${phase}`,
      reason: `${classified.mergeable.length} item(s) ready to merge`,
    };
  }

  // Rule 7: All resolved, no plans
  if (plans.count === 0) {
    return {
      rule: 7,
      command: `/msd:plan-phase ${phase}`,
      reason: 'All items resolved, no plans yet',
    };
  }

  // Rule 8: Plans exist, not executed
  if (!plans.executed) {
    return {
      rule: 8,
      command: `/msd:execute-phase ${phase}`,
      reason: `${plans.count} plan(s) exist, not yet executed`,
    };
  }

  // Rule 9: Everything done
  return { rule: 9, command: null, reason: 'Phase complete' };
}

// ---------------------------------------------------------------------------
// Auto-fix detection (and application with --fix)
// ---------------------------------------------------------------------------

function detectAutoFixes(allItems) {
  const fixes = [];

  for (const item of allItems) {
    // Prerequisite misclassification: CONTEXT/RESEARCH target with prerequisite: yes
    if (item.prerequisite && item.target && /^(CONTEXT|RESEARCH)$/i.test(item.target.trim())) {
      fixes.push({
        id: item.id,
        file: item.file,
        line: item.line,
        type: 'prereq_miscategorized',
        field: 'prerequisite',
        from: 'yes',
        to: 'no (auto-fixed: CONTEXT/RESEARCH target → plan sequencing, not code prerequisite)',
        description: `${item.target} target cannot have prerequisite: yes — plan sequencing, not code dependency`,
      });
    }

    // Status normalization: detect common typos/case issues
    if (item.status_raw && !ALL_STATUSES.has(item.status)) {
      // Try case-insensitive match
      const normalized = item.status_raw.toLowerCase().trim().split(/\s/)[0];
      if (ALL_STATUSES.has(normalized) && normalized !== item.status) {
        fixes.push({
          id: item.id,
          file: item.file,
          line: item.line,
          type: 'status_normalization',
          field: 'status',
          from: item.status_raw,
          to: normalized,
          description: `Status normalized: "${item.status_raw}" → "${normalized}"`,
        });
      }
    }
  }

  // Duplicate ID detection
  const idCounts = new Map();
  for (const item of allItems) {
    const key = item.id;
    if (!idCounts.has(key)) idCounts.set(key, []);
    idCounts.get(key).push(item);
  }
  for (const [id, items] of idCounts) {
    if (items.length > 1) {
      fixes.push({
        id,
        files: items.map(i => i.file),
        type: 'duplicate_id',
        description: `Duplicate ID "${id}" found in ${items.length} locations`,
      });
    }
  }

  return fixes;
}

function applyFixes(fixes) {
  const fileChanges = new Map();

  for (const fix of fixes) {
    if (fix.type === 'prereq_miscategorized') {
      if (!fileChanges.has(fix.file)) {
        fileChanges.set(fix.file, readFileSync(fix.file, 'utf-8'));
      }
      let content = fileChanges.get(fix.file);
      const lines = content.split('\n');

      // Find the item header line, then find Prerequisite within that item's boundary
      const escapedId = fix.id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const headerRegex = new RegExp(`^###\\s+${escapedId}:`);
      let headerIdx = -1;
      for (let i = 0; i < lines.length; i++) {
        if (headerRegex.test(lines[i])) { headerIdx = i; break; }
      }
      if (headerIdx === -1) continue;

      // Find the end of this item (next ### header or EOF)
      let itemEndIdx = lines.length;
      for (let i = headerIdx + 1; i < lines.length; i++) {
        if (/^###\s+/.test(lines[i])) { itemEndIdx = i; break; }
      }

      // Find and fix the Prerequisite line within this item's boundary only
      let prereqFixed = false;
      let prereqLineIdx = -1;
      for (let i = headerIdx + 1; i < itemEndIdx; i++) {
        const prereqMatch = lines[i].match(/^(\*\*Prerequisite:\*\*\s*)yes\b(.*)/);
        if (prereqMatch) {
          const suffix = prereqMatch[2] || '';
          const originalText = suffix.replace(/^\s*--\s*/, '').trim();
          lines[i] = `${prereqMatch[1]}no -- auto-fixed: plan sequencing, not code prerequisite${originalText ? '. Original: ' + originalText : ''}`;
          prereqFixed = true;
          prereqLineIdx = i;
          break;
        }
      }

      if (!prereqFixed) continue;

      // Check if depends_on_plans already exists within this item
      let hasDependsOnPlans = false;
      for (let i = headerIdx + 1; i < itemEndIdx; i++) {
        if (/^\*\*Depends on plans:\*\*/.test(lines[i])) { hasDependsOnPlans = true; break; }
      }

      // Add depends_on_plans after the prerequisite line if not present
      if (!hasDependsOnPlans && prereqLineIdx >= 0) {
        lines.splice(prereqLineIdx + 1, 0, '**Depends on plans:** (from auto-fix: see original prerequisite text)');
        itemEndIdx++; // account for inserted line
      }

      content = lines.join('\n');
      fileChanges.set(fix.file, content);
    }
  }

  // Write all changed files and verify fixes applied correctly
  const written = [];
  for (const [filePath, content] of fileChanges) {
    writeFileSync(filePath, content, 'utf-8');
    written.push(filePath);
  }

  // Post-fix verification: re-parse to confirm no cross-boundary corruption
  for (const filePath of written) {
    const reparsed = parseImprovementFile(filePath);
    for (const item of reparsed.items) {
      // Verify no item lost its prerequisite field entirely
      if (item.prerequisite_raw === null && item.prerequisite === false) continue; // never had one
    }
  }

  return written;
}

// ---------------------------------------------------------------------------
// Convergence metrics (count-based — NOT semantic classification)
// ---------------------------------------------------------------------------

function computeConvergence(allItems) {
  let novel_structural = 0;
  let maintenance_structural = 0;
  let cosmetic_count = 0;
  let unclassified = 0;

  for (const item of allItems) {
    if (TERMINAL_STATUSES.has(item.status)) continue; // Skip terminal items

    const cls = item.classification;
    const isStructural = cls === 'structural' || cls === 'creative-structural'
      || (!cls && (inferStructural(item) || inferCreativeStructural(item)));

    if (!cls) unclassified++;

    if (isStructural) {
      if (inferMaintenanceStructural(item)) {
        maintenance_structural++;
      } else {
        novel_structural++;
      }
    } else {
      cosmetic_count++;
    }
  }

  const structural_count = novel_structural + maintenance_structural;
  const total = structural_count + cosmetic_count;
  const ratio = total > 0 ? Math.round((cosmetic_count / total) * 100) : 0;
  const maintenance_ratio = total > 0
    ? Math.round(((maintenance_structural + cosmetic_count) / total) * 100) : 0;

  return { structural_count, novel_structural, maintenance_structural,
           cosmetic_count, total, ratio, maintenance_ratio, unclassified };
}

function inferStructural(item) {
  // Target is PLAN-*, or prerequisite: yes, or How mentions create/split/merge/delete plan,
  // or What references <domain> or assumptions
  if (item.target && /^PLAN-/i.test(item.target)) return true;
  if (item.prerequisite) return true;
  if (item.how && /\b(create|split|merge|delete)\s+plan/i.test(item.how)) return true;
  if (item.what && /(<domain>|assumption)/i.test(item.what)) return true;
  return false;
}

function inferCreativeStructural(item) {
  // What/Why mentions reframing/mental model/scope shift with cosmetic How
  if (!item.what && !item.why) return false;
  const combined = (item.what || '') + ' ' + (item.why || '');
  return /\b(refram|mental model|scope shift)/i.test(combined);
}

/**
 * Two-stage heuristic for maintenance-structural classification.
 * Stage 1: Explicit Origin field (highest confidence)
 * Stage 2: Keyword match (high recall)
 * Stage 3: Novelty counter-check (prevents false positives)
 */
function inferMaintenanceStructural(item) {
  const combined = (item.what || '') + ' ' + (item.why || '');

  // Stage 1: Explicit origin field (highest confidence)
  if (item.origin && /derivative|deducible/i.test(item.origin)) return true;

  // Stage 2: Keyword patterns (high recall, needs novelty check)
  const hasMaintenanceKeyword =
    /\b(prior pass|previous pass|P\d+-IMP|P\d+-ADV|P\d+-SYN|pass \d)/i.test(combined) ||
    /\b(unif|align|consistent|mismatch|naming convention|enum.*value|field.*name)/i.test(combined);

  if (!hasMaintenanceKeyword) return false;

  // Stage 3: Novelty counter-check (prevents false positives)
  // If item uses maintenance language but in a genuinely novel context, it's not maintenance
  const hasNoveltySignal =
    /\b(new vulnerability|discovered|execution failure|not previously|attack vector|economic model|novel|genuinely new)/i.test(combined);

  if (hasNoveltySignal) return false; // Keyword hit + novelty signal = not maintenance

  return true;
}

// ---------------------------------------------------------------------------
// Dedup detection (--dedup)
// ---------------------------------------------------------------------------

/** Normalize a field value for dedup comparison: lowercase, collapse whitespace, strip punctuation. */
function normalizeForDedup(value) {
  if (!value) return '';
  return value
    .toLowerCase()
    .replace(/[^\w\s]/g, '')   // strip punctuation
    .replace(/\s+/g, ' ')      // collapse whitespace
    .trim();
}

/** Compute Jaccard word-overlap score between two strings. */
function jaccardScore(a, b) {
  const wordsA = new Set(normalizeForDedup(a).split(' ').filter(Boolean));
  const wordsB = new Set(normalizeForDedup(b).split(' ').filter(Boolean));
  if (wordsA.size === 0 && wordsB.size === 0) return 1.0;
  if (wordsA.size === 0 || wordsB.size === 0) return 0.0;

  let intersection = 0;
  for (const w of wordsA) {
    if (wordsB.has(w)) intersection++;
  }
  const union = new Set([...wordsA, ...wordsB]).size;
  return union > 0 ? intersection / union : 0;
}

/**
 * Compute cross-pass duplicate detection and similarity hints.
 *
 * Returns: { duplicates: [...], similarity_hints: [...] }
 *
 * State guards:
 * - Only items with status 'open' can be superseded (the "original" side).
 * - The superseding item (later pass) must NOT be in a terminal state.
 * - If the superseding item is itself superseded or rejected, skip.
 */
function computeDedup(allItems) {
  const duplicates = [];
  const similarityHints = [];

  // Statuses that protect an item from being superseded
  const PROTECTED_STATUSES = new Set(['confirmed', 'enhanced', 'researched', 'pre-implemented']);

  for (let i = 0; i < allItems.length; i++) {
    for (let j = i + 1; j < allItems.length; j++) {
      const a = allItems[i];
      const b = allItems[j];

      // Only cross-pass comparisons
      if (a.pass === b.pass) continue;

      const normTargetA = normalizeForDedup(a.target);
      const normTargetB = normalizeForDedup(b.target);
      const normWhatA = normalizeForDedup(a.what);
      const normWhatB = normalizeForDedup(b.what);

      // Skip items with missing target or what
      if (!normTargetA || !normTargetB) continue;

      // Determine earlier and later by pass number
      const [earlier, later] = a.pass < b.pass ? [a, b] : [b, a];

      // --- Exact-match detection ---
      if (normTargetA === normTargetB && normWhatA === normWhatB && normWhatA !== '') {
        // State guard: only supersede 'open' items
        if (earlier.status !== 'open') continue;
        // State guard: protected statuses cannot be superseded
        if (PROTECTED_STATUSES.has(earlier.status)) continue;
        // State guard: superseding item must not be terminal
        if (TERMINAL_STATUSES.has(later.status)) continue;
        // State guard: superseding item must not itself be superseded or rejected
        if (later.status === 'superseded' || later.status === 'rejected') continue;

        duplicates.push({
          original: earlier.id,
          superseded_by: later.id,
          match: 'exact',
          target: earlier.target,
          what_preview: (earlier.what || '').slice(0, 50),
        });
        continue;
      }

      // --- Jaccard similarity hints ---
      if (normTargetA === normTargetB && normWhatA !== '' && normWhatB !== '') {
        const score = jaccardScore(a.what, b.what);
        if (score >= 0.4) {
          similarityHints.push({
            id_a: a.id,
            id_b: b.id,
            jaccard_score: Math.round(score * 100) / 100,
            target: a.target,
          });
        }
      }
    }
  }

  return { duplicates, similarity_hints: similarityHints };
}

/**
 * Apply dedup supersessions to files given the dedup result and allItems for file lookup.
 * Sets status to 'superseded' and adds superseded_by field on the original item.
 * Uses the same bounded line-by-line approach as applyFixes().
 */
function applyDedupToFiles(dedupResult, allItems) {
  const fileChanges = new Map();
  const written = [];

  // Build item lookup by ID
  const itemById = new Map();
  for (const item of allItems) {
    itemById.set(item.id, item);
  }

  for (const dup of dedupResult.duplicates) {
    const item = itemById.get(dup.original);
    if (!item) continue;

    if (!fileChanges.has(item.file)) {
      fileChanges.set(item.file, readFileSync(item.file, 'utf-8'));
    }
    let content = fileChanges.get(item.file);
    const lines = content.split('\n');

    // Find the item header line
    const escapedId = item.id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const headerRegex = new RegExp(`^###\\s+${escapedId}:`);
    let headerIdx = -1;
    for (let i = 0; i < lines.length; i++) {
      if (headerRegex.test(lines[i])) { headerIdx = i; break; }
    }
    if (headerIdx === -1) continue;

    // Find the end of this item (next ### header or EOF)
    let itemEndIdx = lines.length;
    for (let i = headerIdx + 1; i < lines.length; i++) {
      if (/^###\s+/.test(lines[i])) { itemEndIdx = i; break; }
    }

    // Find and update the Status line within this item's boundary
    let statusFixed = false;
    for (let i = headerIdx + 1; i < itemEndIdx; i++) {
      const statusMatch = lines[i].match(/^(\*\*Status:\*\*\s*)(.*)/);
      if (statusMatch) {
        lines[i] = `${statusMatch[1]}superseded`;
        statusFixed = true;
        break;
      }
    }

    // If no status line found, insert one after header
    if (!statusFixed) {
      lines.splice(headerIdx + 1, 0, `**Status:** superseded`);
      itemEndIdx++;
    }

    // Check if superseded_by already exists within this item
    let hasSupersededBy = false;
    for (let i = headerIdx + 1; i < itemEndIdx; i++) {
      if (/^\*\*Superseded[_ ]by:\*\*/.test(lines[i])) {
        // Update existing
        lines[i] = `**Superseded_by:** ${dup.superseded_by}`;
        hasSupersededBy = true;
        break;
      }
    }

    // Add superseded_by after status line if not present
    if (!hasSupersededBy) {
      for (let i = headerIdx + 1; i < itemEndIdx; i++) {
        if (/^\*\*Status:\*\*/.test(lines[i])) {
          lines.splice(i + 1, 0, `**Superseded_by:** ${dup.superseded_by}`);
          break;
        }
      }
    }

    content = lines.join('\n');
    fileChanges.set(item.file, content);
  }

  // Write all changed files
  for (const [filePath, content] of fileChanges) {
    writeFileSync(filePath, content, 'utf-8');
    written.push(filePath);
  }

  return written;
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function main() {
  // Staleness cache: reuse .tmp-pipeline.json if no IMPROVEMENT file has been modified
  const tmpPath = path.join(phaseDir, '.tmp-pipeline.json');
  if (!doFix && !doDedup && !doIntegrity && existsSync(tmpPath)) {
    try {
      const tmpStat = statSync(tmpPath);
      const improvementFiles = readdirSync(phaseDir).filter(f => /^IMPROVEMENT-P\d+\.md$/.test(f));
      const anyNewer = improvementFiles.some(f => {
        const fStat = statSync(path.join(phaseDir, f));
        return fStat.mtimeMs > tmpStat.mtimeMs;
      });
      if (!anyNewer && improvementFiles.length > 0) {
        const cached = JSON.parse(readFileSync(tmpPath, 'utf-8'));
        if (!jsonOnly) console.error('Using cached pipeline classification');
        console.log(JSON.stringify(cached));
        process.exit(0);
      }
    } catch (e) {
      // Cache read failed, continue with fresh classification
    }
  }

  // 1. Find and parse all IMPROVEMENT files
  const improvementFiles = [];
  if (existsSync(phaseDir)) {
    const files = readdirSync(phaseDir)
      .filter(f => /^IMPROVEMENT-P\d+\.md$/i.test(f))
      .sort();
    for (const f of files) {
      improvementFiles.push(parseImprovementFile(path.join(phaseDir, f)));
    }
  }

  // Collect all items across all files
  const allItems = improvementFiles.flatMap(f => f.items);

  // 2. Classify items
  const classified = classifyItems(allItems);

  // 3. Parse gaps
  const gaps = parseGaps(path.join(phaseDir, 'gaps'));

  // 4. Check CONTEXT.md
  const context = checkContext(phaseDir, paddedPhase);

  // 5. Check plans
  const plans = checkPlans(phaseDir);

  // 6. Compute pipeline string
  const pipelineString = computePipelineString(classified, context, gaps, plans);

  // 7. Compute routing
  const routing = computeRouting(classified, context, gaps, plans, paddedPhase, allItems);

  // 8. Detect auto-fixes
  const autoFixes = detectAutoFixes(allItems);

  // 9. Compute convergence
  const convergence = computeConvergence(allItems);

  // 10. Apply fixes if --fix
  let fixesApplied = [];
  if (doFix && autoFixes.length > 0) {
    fixesApplied = applyFixes(autoFixes);
  }

  // 11. Dedup detection if --dedup
  let dedupResult = null;
  let dedupFilesWritten = [];
  if (doDedup) {
    dedupResult = computeDedup(allItems);
    // Apply dedup fixes if --dedup --fix
    if (doFix && dedupResult.duplicates.length > 0) {
      dedupFilesWritten = applyDedupToFiles(dedupResult, allItems);
    }
  }

  // 12. Structural integrity checks if --integrity
  let integrityReport = null;
  if (doIntegrity) {
    integrityReport = checkIntegrity(phaseDir, paddedPhase);
  }

  // Build output
  const counts = (arr) => arr.length;
  const ids = (arr) => arr.map(i => i.id);

  const output = {
    phase_dir: phaseDir,
    padded_phase: paddedPhase,
    context_status: context.status,
    context: {
      exists: context.exists,
      status: context.status,
      lines: context.lines || 0,
    },
    improvement_files: improvementFiles.map(f => ({
      file: path.basename(f.filePath),
      pass: f.passNumber,
      status: f.fileStatus,
      item_count: f.items.length,
    })),
    items: {
      total: classified.total,
      prereqs_all: counts(classified.prereqs_all),
      prereqs_miscategorized: counts(classified.prereqs_miscategorized),
      prereqs_pending: counts(classified.prereqs_pending),
      prereqs_built: counts(classified.prereqs_built),
      prereqs_ready: counts(classified.prereqs_ready),
      research_dependent_prereqs: counts(classified.research_dependent_prereqs),
      research_pending: counts(classified.research_pending),
      research_done: counts(classified.research_done),
      research_only: counts(classified.research_only),
      adv_unvalidated: counts(classified.adv_unvalidated),
      imp_unreviewed: counts(classified.imp_unreviewed),
      mergeable: counts(classified.mergeable),
      implemented: counts(classified.implemented),
      reframed: counts(classified.reframed),
      rejected: counts(classified.rejected),
      deferred: counts(classified.deferred),
      not_needed: counts(classified.not_needed),
      failed: counts(classified.failed_items),
      open: counts(classified.open_items),
    },
    item_ids: {
      prereqs_pending: ids(classified.prereqs_pending),
      prereqs_miscategorized: ids(classified.prereqs_miscategorized),
      research_pending: ids(classified.research_pending),
      adv_unvalidated: ids(classified.adv_unvalidated),
      imp_unreviewed: ids(classified.imp_unreviewed),
      mergeable: ids(classified.mergeable),
      failed: ids(classified.failed_items),
      reframed: ids(classified.reframed),
    },
    item_details: allItems.map(item => ({
      id: item.id,
      title: item.title,
      pass: item.pass,
      file: path.basename(item.file),
      status: item.status,
      target: item.target,
      what: item.what,
      why: item.why,
      how: item.how,
      impacts: item.impacts,
      research_needed: item.research_needed,
      research_needed_raw: item.research_needed_raw,
      confidence: item.confidence,
      prior_art: item.prior_art,
      prerequisite: item.prerequisite,
      prerequisite_raw: item.prerequisite_raw,
      depends_on_plans: item.depends_on_plans,
      classification: item.classification,
      components: item.components || null,
      trigger: item.trigger || null,
      replaces: item.replaces || null,
      origin: item.origin,
      review_status: item.review_status,
      superseded_by: item.superseded_by,
      research_summary: item.research_summary,
      pre_implement_note: item.pre_implement_note,
    })),
    merge_groups: (() => {
      const groups = new Map();
      for (const item of classified.mergeable) {
        const target = (item.target || 'CONTEXT').trim().toUpperCase();
        // For CONTEXT items, try to extract section from How field
        let section = null;
        if (target === 'CONTEXT' && item.how) {
          // Look for section references like "in the <plans> section" or "assumptions section"
          const sectionMatch = item.how.match(/(?:in\s+(?:the\s+)?)?<(\w+)>\s*section|(\w+)\s+section/i);
          if (sectionMatch) section = sectionMatch[1] || sectionMatch[2];
        }
        const key = section ? `${target}:${section}` : target;
        if (!groups.has(key)) {
          groups.set(key, { target, section, item_ids: [] });
        }
        groups.get(key).item_ids.push(item.id);
      }
      return Array.from(groups.values());
    })(),
    gaps: {
      active: gaps.active,
      disputed: gaps.disputed,
      resolved: gaps.resolved,
    },
    plans: {
      count: plans.count,
      executed: plans.executed,
      files: plans.files,
    },
    pipeline_string: pipelineString,
    routing,
    auto_fixes: autoFixes,
    convergence,
    fixes_applied: doFix ? fixesApplied : undefined,
    duplicates: dedupResult ? dedupResult.duplicates : undefined,
    similarity_hints: dedupResult ? dedupResult.similarity_hints : undefined,
    dedup_files_written: doDedup && doFix && dedupFilesWritten.length > 0 ? dedupFilesWritten : undefined,
    integrity_report: integrityReport,
  };

  // Write to .tmp-pipeline.json (skip if dir doesn't exist)
  const outputPath = path.join(phaseDir, '.tmp-pipeline.json');
  if (existsSync(phaseDir)) {
    writeFileSync(outputPath, JSON.stringify(output, null, 2), 'utf-8');
  }

  // Print to stdout
  if (jsonOnly) {
    console.log(JSON.stringify(output, null, 2));
  } else {
    // Summary output
    console.log(`Pipeline Classification: ${paddedPhase}`);
    console.log('='.repeat(40));
    console.log(`CONTEXT: ${context.status}${context.lines ? ` (${context.lines} lines)` : ''}`);
    console.log(`Items: ${classified.total} total`);
    if (classified.prereqs_pending.length > 0) console.log(`  Prereqs pending: ${classified.prereqs_pending.length}`);
    if (classified.prereqs_built.length > 0) console.log(`  Prereqs built: ${classified.prereqs_built.length}`);
    if (classified.research_pending.length > 0) console.log(`  Research pending: ${classified.research_pending.length}`);
    if (classified.research_done.length > 0) console.log(`  Research done: ${classified.research_done.length}`);
    if (classified.mergeable.length > 0) console.log(`  Mergeable: ${classified.mergeable.length}`);
    if (classified.implemented.length > 0) console.log(`  Implemented: ${classified.implemented.length}`);
    if (classified.imp_unreviewed.length > 0) console.log(`  IMP unreviewed: ${classified.imp_unreviewed.length}`);
    if (classified.adv_unvalidated.length > 0) console.log(`  ADV unvalidated: ${classified.adv_unvalidated.length}`);
    if (classified.prereqs_miscategorized.length > 0) console.log(`  Miscategorized prereqs: ${classified.prereqs_miscategorized.length}`);
    console.log(`Gaps: ${gaps.active} active, ${gaps.disputed} disputed, ${gaps.resolved} resolved`);
    console.log(`Plans: ${plans.count} (executed: ${plans.executed})`);
    console.log(`\n${pipelineString}`);
    console.log(`\nRoute: Rule #${routing.rule} → ${routing.command || '(none)'}`);
    console.log(`  ${routing.reason}`);
    if (convergence.total > 0) {
      console.log(`\nConvergence: ${convergence.ratio}% cosmetic (${convergence.cosmetic_count}/${convergence.total})`);
      if (convergence.maintenance_ratio !== undefined) {
        console.log(`  Value filter: Novel: ${convergence.novel_structural}  |  Maintenance: ${convergence.maintenance_structural}`);
        console.log(`  Maintenance ratio: ${convergence.maintenance_ratio}%`);
        if (convergence.maintenance_ratio > 80) {
          console.log(`  CONVERGENCE SIGNAL: Maintenance items dominate. Consider stopping.`);
        } else if (convergence.maintenance_ratio > 60) {
          console.log(`  WARNING: Self-justifying loop pattern detected.`);
        }
      }
    }
    if (autoFixes.length > 0) {
      console.log(`\nAuto-fixes available: ${autoFixes.length}`);
      for (const fix of autoFixes) {
        console.log(`  ${fix.id}: ${fix.description}`);
      }
      if (doFix) {
        console.log(`\nFixes applied to: ${fixesApplied.join(', ')}`);
      }
    }
    if (dedupResult) {
      if (dedupResult.duplicates.length > 0) {
        console.log(`\nDuplicates detected: ${dedupResult.duplicates.length}`);
        for (const dup of dedupResult.duplicates) {
          console.log(`  ${dup.original} → superseded by ${dup.superseded_by} (${dup.match})`);
        }
        if (doFix && dedupFilesWritten.length > 0) {
          console.log(`  Dedup fixes applied to: ${dedupFilesWritten.join(', ')}`);
        }
      }
      if (dedupResult.similarity_hints.length > 0) {
        console.log(`\nSimilarity hints: ${dedupResult.similarity_hints.length}`);
        for (const hint of dedupResult.similarity_hints) {
          console.log(`  ${hint.id_a} ~ ${hint.id_b} (jaccard: ${hint.jaccard_score}, target: ${hint.target})`);
        }
      }
      if (dedupResult.duplicates.length === 0 && dedupResult.similarity_hints.length === 0) {
        console.log('\nDedup: no duplicates or similar items found');
      }
    }
    if (integrityReport) {
      const totalIssues = integrityReport.wave_inversions.length + integrityReport.file_conflicts.length;
      console.log(`\nIntegrity: ${integrityReport.plans_checked} plans checked`);
      if (integrityReport.error) {
        console.log(`  ERROR: ${integrityReport.error}`);
      } else if (totalIssues === 0) {
        console.log('  No wave inversions or file conflicts detected');
      } else {
        if (integrityReport.wave_inversions.length > 0) {
          console.log(`  Wave inversions: ${integrityReport.wave_inversions.length}`);
          for (const inv of integrityReport.wave_inversions) {
            console.log(`  [${inv.severity}] ${inv.message}`);
          }
        }
        if (integrityReport.file_conflicts.length > 0) {
          console.log(`  File conflicts: ${integrityReport.file_conflicts.length}`);
          for (const conf of integrityReport.file_conflicts) {
            console.log(`  [${conf.severity}] ${conf.message}`);
          }
        }
      }
    }
    console.log(`\nOutput: ${outputPath}`);
  }
}

main();

