// Step 4-5: Write file, call pipeline-classify, rewrite with pipeline status
// ---------------------------------------------------------------------------

const outputFile = path.join(phaseDir, `IMPROVEMENT-P${passNumber}.md`);

// First write — without pipeline status (so pipeline-classify can read it)
writeFileSync(outputFile, buildFileContent(null), 'utf-8');

// Call pipeline-classify.js
let pipeline = null;
let pipelineSection = '';
try {
  const scriptDir = path.dirname(fileURLToPath(import.meta.url));
  const pipelineResult = execSync(
    `node ${path.join(scriptDir, 'pipeline-classify.js')} --phase-dir "${phaseDir}" --padded "${paddedPhase}" --json`,
