const phaseDir = getArg('phase-dir');
const paddedPhase = getArg('padded');
const passNumber = parseInt(getArg('pass') || '0', 10);
const expectedCount = parseInt(getArg('expected') || '0', 10);

if (!phaseDir || !paddedPhase || !passNumber) {
  console.error(`Usage: merge-improvements.js --phase-dir <dir> --padded <NN> --pass <N> --expected <count>`);
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Step 1: Read temp files and validate count
// ---------------------------------------------------------------------------

const warnings = [];
const tmpFiles = readdirSync(phaseDir)
  .filter(f => /^\.tmp-improve-.*\.md$/.test(f))
  .sort();

if (expectedCount > 0 && tmpFiles.length !== expectedCount) {
  const msg = `Expected ${expectedCount} temp files, found ${tmpFiles.length}`;
  console.error(`Warning: ${msg}`);
  warnings.push(msg);
}

if (tmpFiles.length === 0) {
  console.error('Error: No .tmp-improve-*.md files found');
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Step 2: Parse improvement items and convergence sections from each file
// ---------------------------------------------------------------------------

const allItems = [];
const convergenceSections = [];
const itemsPerArea = {};

for (const filename of tmpFiles) {
  const areaSlug = filename.replace(/^\.tmp-improve-/, '').replace(/\.md$/, '');
  const filePath = path.join(phaseDir, filename);
  const content = readFileSync(filePath, 'utf-8');
  const lines = content.split('\n');

  let areaCount = 0;
  let currentItem = null;
  let currentFieldName = null;
  let convergenceStart = -1;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Detect convergence assessment section
    if (/^##\s+Convergence Assessment/i.test(line)) {
      convergenceStart = i;
      if (currentItem) { allItems.push(currentItem); currentItem = null; areaCount++; }
      // Capture everything from here to end of file or next ## (non-convergence)
      let convergenceEnd = lines.length;
      for (let j = i + 1; j < lines.length; j++) {
        if (/^##\s+/.test(lines[j]) && !/^##\s+Convergence/i.test(lines[j])) {
          convergenceEnd = j;
          break;
        }
      }
      convergenceSections.push({
        area: areaSlug,
        content: lines.slice(i, convergenceEnd).join('\n'),
      });
      i = convergenceEnd - 1;
      continue;
    }

    // Detect item header: ### P{N}-IMP-{NN}: Title (and variants incl. coordination)
    const headerMatch = line.match(/^###\s+(P\d+-(?:IMP|ADV|SYN|CSC|ALN|COORD-STRUCT|COORD-EXP|COORD-GAP)(?:-[A-Z]*)?-\d+):\s*(.+)/);
    if (headerMatch) {
      if (currentItem) { allItems.push(currentItem); areaCount++; }
      currentItem = {
        id: headerMatch[1],
        title: headerMatch[2].trim(),
        area: areaSlug,
        fields: [],
      };
      currentFieldName = null;
      continue;
    }

    if (!currentItem) continue;

    // Parse **Field:** value with scan-ahead for multi-line values
    // (aligned with pipeline-classify.js pattern: continue until blank, new field, or header)
    const fieldMatch = line.match(/^\*\*(.+?):\*\*\s*(.*)/);
    if (fieldMatch) {
      currentFieldName = fieldMatch[1];
      let fieldValue = fieldMatch[2];
      let j = i + 1;
      while (j < lines.length) {
        const nextLine = lines[j];
        if (nextLine.trim() === '' || /^\*\*.+?:\*\*/.test(nextLine) || /^###\s+/.test(nextLine)) break;
        fieldValue += '\n' + nextLine;
        j++;
