// Step 2b: Validate — detect format mismatches (WARN-only, never blocking)
// ---------------------------------------------------------------------------

const validation = [];

for (const filename of tmpFiles) {
  const filePath = path.join(phaseDir, filename);
  // File may have been deleted already if this runs after cleanup, but we read it earlier
  // so check itemsPerArea for the slug
  const areaSlug = filename.replace(/^\.tmp-improve-/, '').replace(/\.md$/, '');
  const parsedCount = itemsPerArea[areaSlug] || 0;

  if (parsedCount === 0) {
    // Re-read to check if file had content that should have been parsed
    let content;
    try { content = readFileSync(filePath, 'utf-8'); } catch { continue; }
